import urllib.request
import urllib.error
import json
import time

class ThreatIntelClient:
    """Client générique pour les APIs de Threat Intelligence."""

    def __init__(self, base_url, api_key=None, key_header="x-apikey"):
        self.base_url = base_url
        self.api_key = api_key
        self.key_header = key_header

    def get(self, endpoint, params=None, max_retries=3):
        """Requête GET avec retry automatique sur rate limit."""
        url = self.base_url + endpoint
        if params:
            from urllib.parse import urlencode
            url += "?" + urlencode(params)

        headers = {"Accept": "application/json", "User-Agent": "SOC-Script/1.0"}
        if self.api_key:
            headers[self.key_header] = self.api_key

        for tentative in range(max_retries):
            try:
                req = urllib.request.Request(url, headers=headers)
                with urllib.request.urlopen(req, timeout=15) as resp:
                    return json.loads(resp.read())
            except urllib.error.HTTPError as e:
                if e.code == 429:  # Rate limit
                    print(f"Rate limit. Attente {2**tentative}s...")
                    time.sleep(2 ** tentative)
                else:
                    print(f"HTTP {e.code}: {e.reason}")
                    return None
            except Exception as e:
                print(f"Erreur : {e}")
                return None
        return None
